export async function getEscrowAntPDA(antMint, programId = ARIO_ANT_ESCROW_PROGRAM_ID) {
    return getProgramDerivedAddress({
        programAddress: programId,
        seeds: [ESCROW_ANT_SEED, addressEncoder.encode(antMint)],
    });
}
